insert into public.cities (id, city_name, image_path, hero_image_path, location_text, latitude, longitude, description, is_featured)
values
  ('cty_000001', 'Tirana', 'assets/cities/tirana.jpg', 'assets/cities/tirana.jpg', 'Tirana, Albania', 41.3275, 19.8187, 'Albania''s lively capital with cafes, culture, nightlife and city escapes.', true),
  ('cty_000002', 'Shkodër', 'assets/cities/shkoder.jpg', 'assets/cities/shkoder.jpg', 'Shkoder, Albania', 42.0683, 19.5126, 'Historic northern city known for its culture, cycling and proximity to the Albanian Alps.', false),
  ('cty_000003', 'Vlorë', 'assets/cities/vlore.jpg', 'assets/cities/vlore.jpg', 'Vlore, Albania', 40.4661, 19.4914, 'A coastal gateway where the Adriatic meets the Ionian Sea.', false),
  ('cty_000004', 'Durrës', 'assets/cities/durres.jpg', 'assets/cities/durres.jpg', 'Durres, Albania', 41.3231, 19.4414, 'A seaside city with long beaches, Roman history and easy access from Tirana.', false),
  ('cty_000005', 'Ksamil', 'assets/cities/ksamil.jpg', 'assets/cities/ksamil.jpg', 'Ksamil, Albania', 39.7683, 20.0012, 'A famous southern beach destination with turquoise water and small islands.', true),
  ('cty_000006', 'Dhërmi', 'assets/cities/dhermi.jpg', 'assets/cities/dhermi.jpg', 'Dhermi, Albania', 40.1492, 19.6388, 'A Riviera hotspot known for beaches, nightlife and scenic mountain roads.', false),
  ('cty_000007', 'Lin', 'assets/cities/lin.jpg', 'assets/cities/lin.jpg', 'Lin, Albania', 41.0658, 20.6447, 'A peaceful village on Lake Ohrid with quiet waterfront views.', false),
  ('cty_000008', 'Theth', 'assets/cities/theth.jpg', 'assets/cities/theth.jpg', 'Theth, Albania', 42.3959, 19.7746, 'A mountain village famous for hiking, alpine landscapes and traditional guesthouses.', false),
  ('cty_000009', 'Gjirokaster', 'assets/cities/gjirokaster.jpg', 'assets/cities/gjirokaster.jpg', 'Gjirokaster, Albania', 40.0758, 20.1389, 'A UNESCO stone city with Ottoman-era architecture and castle views.', false),
  ('cty_000010', 'Korca', 'assets/cities/korca.jpg', 'assets/cities/korca.jpg', 'Korca, Albania', 40.6186, 20.7808, 'A southeastern cultural center known for food, serenades and a relaxed city rhythm.', false),
  ('cty_000011', 'Berat', 'assets/cities/berat.jpg', 'assets/cities/berat.jpg', 'Berat, Albania', 40.7058, 19.9522, 'The city of a thousand windows with layered history and riverside charm.', true),
  ('cty_000012', 'Lezhe', 'assets/cities/lezhe.jpg', 'assets/cities/lezhe.jpg', 'Lezhe, Albania', 41.7861, 19.6461, 'A northern city that connects inland landmarks with nearby beaches and lagoons.', false),
  ('cty_000013', 'Shengjin', 'assets/cities/lezhe.jpg', 'assets/cities/lezhe.jpg', 'Shengjin, Albania', 41.8131, 19.5938, 'A growing beach destination on the northern coast.', false),
  ('cty_000014', 'Velipoje', 'assets/cities/lezhe.jpg', 'assets/cities/lezhe.jpg', 'Velipoje, Albania', 41.8632, 19.4184, 'A wide sandy beach area near natural reserves and the Montenegro border.', false),
  ('cty_000015', 'Saranda', 'assets/cities/lezhe.jpg', 'assets/cities/lezhe.jpg', 'Saranda, Albania', 39.8756, 20.0049, 'A sunny Ionian city popular for beaches, promenades and day trips to the south.', true),
  ('cty_000016', 'Kruja', 'assets/cities/kruja.jpg', 'assets/cities/kruja.jpg', 'Kruja, Albania', 41.5092, 19.792, 'A hillside historic town known for Skanderbeg, its bazaar and castle.', false),
  ('cty_000017', 'Himare', 'assets/cities/lezhe.jpg', 'assets/cities/lezhe.jpg', 'Himare, Albania', 40.101, 19.7447, 'A Riviera base for beautiful beaches, bays and laid-back coastal life.', false)
