values
  ('plc_000001', 'cat_000002', 'cty_000001', 'Mullixhiu', 'Mullixhiu offers a modern take on traditional Albanian cuisine, using locally sourced ingredients and seasonal recipes. A must-visit spot in Tirana for an authentic and refined food experience.', 'Shëtitorja Lasgush Poradeci Hyrja e Parkut tek Diga e Liqenit Artificial Tirana, 1019, Albania', 'https://maps.app.goo.gl/J4czqMo29H14oVgT6', 41.320123, 19.830456, 'assets/place/mullixhiu/mullixhiu1.png', '+355696660444', null, 4.1, 1),
  ('plc_000002', 'cat_000002', 'cty_000001', 'Oda Garden', 'A cozy garden restaurant offering traditional Albanian dishes made with fresh, locally sourced ingredients, delivering an authentic and refined dining experience.', 'Rruga Shenasi Dishnica, Tiranë, Albania', 'https://maps.app.goo.gl/sFxb8W921Ka2JdLw7', 41.32959, 19.82448, 'assets/place/odagardenrest/oda1.png', '+355692040145', null, 4.6, 1),
  ('plc_000003', 'cat_000005', 'cty_000001', 'Komiteti Café Museum', 'Unique café with Albanian culture and great coffee. and alcohol ;)', 'Rruga Papa Gjon Pali II, Tiranë, Albania', 'https://maps.app.goo.gl/Gp2FtWZGXnsfk4kh6', 41.32332, 19.82253, 'assets/place/komitetica/komitetica1.png', '+355694452772', null, 4.4, 1),
  ('plc_000004', 'cat_000004', 'cty_000001', 'Radio Bar', 'Popular cocktail bar in Blloku with a lively atmosphere.', 'Rruga Ismail Qemali 1, Tiranë 1000, Albania', 'https://maps.app.goo.gl/xc6mLRfjP7tgd2bq5', 41.32019, 19.81497, 'assets/place/radiobar/radiobar1.png', null, 'radiobar.al', 4.6, 1),
