-- Drite Guide Supabase seed data
-- Generated for local Supabase setup.

on conflict (id) do update set name = excluded.name, image_path = excluded.image_path, updated_at = excluded.updated_at;

on conflict (id) do update set city_name = excluded.city_name, image_path = excluded.image_path, hero_image_path = excluded.hero_image_path, location_text = excluded.location_text, latitude = excluded.latitude, longitude = excluded.longitude, description = excluded.description, is_featured = excluded.is_featured, updated_at = excluded.updated_at;

on conflict (id) do update set category_id = excluded.category_id, city_id = excluded.city_id, name = excluded.name, description = excluded.description, address = excluded.address, google_maps_link = excluded.google_maps_link, latitude = excluded.latitude, longitude = excluded.longitude, main_image_path = excluded.main_image_path, phone = excluded.phone, website = excluded.website, rating_average = excluded.rating_average, ratings_count = excluded.ratings_count, updated_at = excluded.updated_at;

on conflict (id) do update set place_id = excluded.place_id, image_path = excluded.image_path, sort_order = excluded.sort_order;

select setval('public.category_id_seq', 9, true);
select setval('public.city_id_seq', 17, true);
select setval('public.place_id_seq', 51, true);

-- Seeded 9 categories, 17 cities, 51 places and 256 place images.
